-- ===== CROSS JOIN INSERT (모든 SHOWS / PERFORMANCES 에 자동 매핑) =====
SELECT s.id, g.grade_code, g.grade_name,
    CASE g.grade_code
        WHEN 'VIP' THEN 170000
        WHEN 'R' THEN 140000
        WHEN 'S' THEN 110000
        ELSE 80000
    END,
    g.sort_order, '2026-01-01 10:00:00', '시드'
FROM SHOWS s
CROSS JOIN (
    SELECT 'VIP' grade_code, 'VIP석' grade_name, 1 sort_order FROM dual
    UNION ALL SELECT 'R', 'R석', 2 FROM dual
    UNION ALL SELECT 'S', 'S석', 3 FROM dual
    UNION ALL SELECT 'A', 'A석', 4 FROM dual
) g;
SELECT s.id, st.id,
    (SELECT sg.id FROM SHOW_GRADES sg WHERE sg.show_id = s.id AND sg.grade_code = CASE WHEN st.section = '나' THEN 'VIP' WHEN st.section IN ('가', '다') THEN 'R' WHEN st.section IN ('라', '바') THEN 'S' ELSE 'A' END),
    '2026-01-01 10:00:00', '시드'
FROM SHOWS s CROSS JOIN SEATS st;
SELECT p.id, st.id,
    CASE
        WHEN MOD(
            p.id * 17
            + ASCII(SUBSTR(st.section, 1, 1)) * 13
            + ASCII(SUBSTR(st.row_no, 1, 1)) * 7
            + CAST(st.seat_no AS INTEGER) * 11
            + FLOOR((ASCII(SUBSTR(st.row_no, 1, 1)) - ASCII('A')) / 2) * 19
            + FLOOR((CAST(st.seat_no AS INTEGER) - 1) / 3) * 23,
            100
        ) < (
            16 + MOD(p.id, 4) * 4
            + CASE
                WHEN st.section IN ('나', '마') THEN 12
                WHEN st.section IN ('가', '다') THEN 8
                ELSE 5
            END
            + CASE
                WHEN ABS(CAST(st.seat_no AS INTEGER) - 5.5) <= 1 THEN 12
                WHEN ABS(CAST(st.seat_no AS INTEGER) - 5.5) <= 2.5 THEN 7
                ELSE 2
            END
            + CASE
                WHEN st.row_no IN ('C', 'D', 'E', 'F', 'G') THEN 8
                WHEN st.row_no IN ('B', 'H') THEN 4
                ELSE 1
            END
            + CASE
                WHEN MOD(
                    p.id
                    + FLOOR((ASCII(SUBSTR(st.row_no, 1, 1)) - ASCII('A')) / 2)
                    + FLOOR((CAST(st.seat_no AS INTEGER) - 1) / 3),
                    5
                ) = 0 THEN 10
                ELSE 0
            END
            - CASE
                WHEN MOD(
                    p.id * 3
                    + ASCII(SUBSTR(st.section, 1, 1))
                    + ASCII(SUBSTR(st.row_no, 1, 1))
                    + CAST(st.seat_no AS INTEGER) * 5,
                    11
                ) = 0 THEN 12
                ELSE 0
            END
            - MOD(p.id + CAST(st.seat_no AS INTEGER), 5)
        ) THEN 'RESERVED'
        ELSE 'AVAILABLE'
    END,
    (SELECT sg.price FROM SHOW_GRADES sg WHERE sg.show_id = p.show_id AND sg.grade_code = CASE WHEN st.section = '나' THEN 'VIP' WHEN st.section IN ('가', '다') THEN 'R' WHEN st.section IN ('라', '바') THEN 'S' ELSE 'A' END),
    '2026-01-01 10:00:00', '시드'
FROM PERFORMANCES p CROSS JOIN SEATS st;
