INSERT INTO SHOWS (id, title, sub_title, info, start_date, end_date, view_count, sale_type, sale_start_date, sale_end_date, image, venue_id, running_minutes, performer_id, created_at, created_by) VALUES (1, '황문희 피아노 독주회', '예술의전당 [서울] 리사이틀홀', '예술의전당 [서울] 리사이틀홀에서 열리는 이번 클래식 무대는 약 90분 러닝타임으로 운영됩니다. 주요 레퍼토리와 앙상블의 균형을 중심으로 구성됩니다. 세부 프로그램과 출연진 변경 사항은 회차별 공지에서 확인할 수 있습니다.', '2026-03-29', '2026-03-31', 24941, 'GENERAL', '2026-02-13 10:00:00', '2026-04-28 23:59:59', 'https://kopis.or.kr/upload/pfmPoster/PF_PF286025_260227_155957.gif', 1, 90, 1, '2025-06-15 09:30:00', 'KOPIS_SEED');
